API_name: nchu_course_search_by_assessment_method
Description:
{
  "description": "Search courses by assessment/evaluation method. Common assessment methods: 期中考, 期末考, 作業, 報告, 實作, 出席, 小考, 作品, etc. JSON string containing courses using the specified assessment method",
  "required_parameters": [
    {
      "name": "method",
      "type": "STRING",
      "description": "Assessment method to search for (e.g., 實作, 報告, 期末考)"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "Maximum number of results to return (default: 20)",
      "default": 20
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "Semester code. If not specified, uses the latest semester.",
      "default": null
    }
  ]
}

